const parse = (text) => {
  if (!text || typeof text !== 'string') return [];
  const lines = text.trim().split('\n');
  const data = [];
  for (let i = 1; i < lines.length; i++) {
    const parts = lines[i].trim().split(/\s+/);
    if (parts.length === 3) {
      data.push({
        freq: parseFloat(parts[0]),
        spl: parseFloat(parts[1]),
        phase: parseFloat(parts[2]),
      });
    }
  }
  return data;
};

